#include <stdio.h>
int main(){
	int n,k;
	scanf("%d%d",&n,&k);
	int a[n];
	for(int i=0;i<n;i++){
		scanf("%d",&a[i]);
		}
	int cnt=0,i=0,j=n-1;
	int f1=-0,f2=0;
	if(n>1){
		while((f1==0||f2==0)&&(i<=j)){
			if(a[i]<=k){cnt++;i++;}
			else{f1=1;}
			if(a[j]<=k){cnt++;j--;}
			else{f2=1;}
			if(i==j&&a[i]<=k&&a[j]<=k){cnt--;}
			}
		}
		if(n==1&&a[0]<=k){cnt=1;}
		printf("%d\n",cnt);
		return 0;
	}

